import React, { Fragment, useState, useEffect } from 'react';
import { Card, CardHeader, CardBody, Form, Row, Col, Dropdown, DropdownToggle, DropdownMenu, DropdownItem } from 'reactstrap';
import DataTable from 'react-data-table-component';
import { H3, Breadcrumbs, Btn, H4 } from '../../AbstractElements';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { getClientUrlDataToken } from '../../Utils/restUtils';
import { OnlinePaymentRep, OnlinePaymentList, Search, Filter, Export } from '../../Constant';
import { getOnlinePayment, getOnlinePaymentRole } from '../../CommonUrl';
import { useSelector } from 'react-redux';
import { useForm } from 'react-hook-form';
import DatePicker from 'react-datepicker';
import * as XLSX from 'xlsx';
import jsPDF from 'jspdf';
import 'jspdf-autotable';
import moment from 'moment';
import Transparentspinner from '../Common/Loader/Transparentspinner';
import UserDropdown from '../Common Field/UserDropdown';
import AreaDropdown from '../Common Field/AreaDropdown';
import { OnlinePaymentColumns } from './Header/ReportTableHeader';

const OnlinePaymentReport = () => {
    const navigate = useNavigate();
    const location = useLocation();
    const searchParams = location.search;
    const params = new URLSearchParams(searchParams);
    const authState = useSelector((state) => state.auth);
    const [filters, setFilters] = useState({
        search: params.get('search') || '',
        area: params.get('area') || '',
        start_date: params.get('start_date') ? moment(params.get('start_date'), "DD-MM-YYYY").toDate() : '',
        end_date: params.get('end_date') ? moment(params.get('end_date'), "DD-MM-YYYY").toDate() : '',
        sortBy: params.get('sortBy') || '',
        sortOrder: params.get('sortOrder') || '',
        userId: params.get("user") || ''
    });
    const { register, handleSubmit, setValue } = useForm({
        defaultValues: { search: filters.search, area: filters.area, user: filters.userId },
    });
    const [customerLists, setCustomerList] = useState([]);
    const [loading, setLoading] = useState(false);
    const [totalRows, setTotalRows] = useState(0);
    const [perPage, setPerPage] = useState(10);
    const [currentPage, setCurrentPage] = useState(1);
    const [dateRange, setDateRange] = useState([filters.start_date, filters.end_date]);
    const [startDate, endDate] = dateRange
    const toggleStyle = { padding: '10px 20px', opacity: '0.8', fontSize: '14px' };
    const [dropdownOpen, setDropdownOpen] = useState(false);
    const [sortConfig, setSortConfig] = useState({ column: filters.sortBy, order: filters.sortOrder });
    const formatStartDate = filters.start_date ? moment(filters.start_date).format("DD-MM-YYYY") : '';
    const formatEndDate = filters.end_date ? moment(filters.end_date).format("DD-MM-YYYY") : '';
    useEffect(() => {
        fetchOnlinePay(1);
    }, []);

    useEffect(() => {
        setValue('search', filters.search);
    }, [setValue, filters.search]);

    const handleSort = (column) => {
        let newOrder = 'asc';
        if (filters.sortBy === column.id) {
            newOrder = filters.sortOrder === 'asc' ? 'desc' : 'asc';
            setSortConfig({ column: column.id, order: newOrder });
            navigate(`/report/online-payment?search=${filters.search}&start_date=${formatStartDate}&end_date=${formatEndDate}&area=${filters.area}&user=${filters.userId}&sortBy=${column.id}&sortOrder=${newOrder}`);
        } else {
            newOrder = filters.sortOrder === 'asc' ? 'desc' : 'asc';
            setSortConfig({ column: column.id, order: newOrder });
            navigate(`/report/online-payment?search=${filters.search}&start_date=${formatStartDate}&end_date=${formatEndDate}&area=${filters.area}&user=${filters.userId}&sortBy=${column.id}&sortOrder=${newOrder}`);
        }
    };

    const toggleDropdown = () => setDropdownOpen(!dropdownOpen);

    const handleApiError = (status) => {
        if (status >= 400 && status <= 405) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (status >= 500 && status <= 505) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        } else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
        }
    };

    const handlePageChange = page => {
        fetchOnlinePay(page);
        setCurrentPage(page);
    };

    const handlePerRowsChange = async (newPerPage, page) => {
        fetchOnlinePay(page, newPerPage);
        setPerPage(newPerPage);
    };

    const onSubmit = async (data) => {
        const searchKey = data.search || '';
        const start_date = startDate ? moment(startDate).format("DD-MM-YYYY") : '';
        const end_date = endDate ? moment(endDate).format("DD-MM-YYYY") : '';
        const areaFilter = data.area || '';
        const userId = data.user || '';
        const queryParams = new URLSearchParams({
            search: searchKey,
            start_date,
            end_date,
            area: areaFilter,
            user: userId,
            sortBy: sortConfig.column || '',
            sortOrder: sortConfig.order || '',
        }).toString();
        navigate(`/report/online-payment?${queryParams}`);
        setFilters({
            searchKey,
            start_date,
            end_date,
            areaFilter,
            userId
        });
        fetchOnlinePay(currentPage, perPage);
    };

    const fetchOnlinePay = async (page, size = perPage) => {
        setLoading(true);
        const response = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? getOnlinePayment +
            `?page=${page}&page_length=${size}&search=${filters.search}&start_date=${formatStartDate}
            &end_date=${formatEndDate} &area_id=${filters.area}&sort_by=${sortConfig.column ? sortConfig.column : ''}
            &user_id=${filters.userId}&sort_order=${sortConfig.order ? sortConfig.order : ''}` :
            getOnlinePaymentRole + `?page=${page}&page_length=${size}&search=${filters.search}&start_date=${formatStartDate}
            &end_date=${formatEndDate} &area_id=${filters.area}&user_id=${filters.userId}
            &sort_by=${sortConfig.column ? sortConfig.column : ''}&sort_order=${sortConfig.order ? sortConfig.order : ''}`);
        if (response.status === true) {
            const api_data = response.data.data;
            const SerialNo = (page - 1) * size + 1;
            setCustomerList(api_data.map((e, index) => {
                return {
                    Si: SerialNo + index,
                    id: index,
                    SubId: e.subscriber_id,
                    InvoiceNo: e.invoice_no,
                    Name: e.customer_name,
                    Address: e.billing_address,
                    Area: e.area_name,
                    Account: e.account_name,
                    AmountPaid: `${authState.currency} ${e.paid_amount}`,
                    PaidDate: e.paid_date,
                    PaidBy: e.paid_by,
                    orderId: e.order_id,
                    customer_id: e.customer_id,
                }
            }
            ))
            setTotalRows(response.data.total);
        } else {
            handleApiError(data.status);
        }
        setLoading(false);
    };

    const exportOnlinePayExcel = async () => {
        setLoading(true);
        const response = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? getOnlinePayment +
            `?export=online_payment_data&search=${filters?.search ?? ''}&area_id=${filters?.areaFilter ?? ''}&user_id=${filters.userId}&start_date=${formatStartDate ?? ''}&end_date=${formatEndDate ?? ''}&sort_by=${sortConfig.column}&sort_order=${sortConfig.order}` :
            getOnlinePaymentRole + `?export=online_payment_data&search=${filters?.search ?? ''}&area_id=${filters?.area ?? ''}&user_id=${filters.userId}&start_date=${formatStartDate ?? ''}&end_date=${formatEndDate ?? ''}&sort_by=${sortConfig.column ? sortConfig.column : ''}&sort_order=${sortConfig.order ? sortConfig.order : ''}`);
        const dataToExport = response.data.map(({ subscriber_id, invoice_no, customer_name, billing_address, area_name, account_name, paid_amount, paid_date, paid_by }) => ({ Subscriber_Id: subscriber_id, Invoice_No: invoice_no, Name: customer_name, Address: billing_address, Area: area_name, Account: account_name, Amount_Paid: paid_amount, Paid_Date: paid_date, Paid_By: paid_by }));
        if (response.status === true) {
            const ws = XLSX.utils.json_to_sheet(dataToExport);
            const wb = XLSX.utils.book_new();
            XLSX.utils.book_append_sheet(wb, ws, 'online_report');
            XLSX.writeFile(wb, 'online_payment_report_data.xlsx');
        } else {
            handleApiError(data.status);
        }
        setLoading(false);
    };

    const exportOnlinePayPdf = async () => {
        setLoading(true);
        const response = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? getOnlinePayment +
            `?export=online_payment_data&search=${filters?.search ?? ''}&area_id=${filters?.area ?? ''}&user_id=${filters.userId}&start_date=${formatStartDate ?? ''}&end_date=${formatEndDate ?? ''}&sort_by=${sortConfig.column}&sort_order=${sortConfig.order}` :
            getOnlinePaymentRole + `?export=online_payment_data&search=${filters?.search ?? ''}&area_id=${filters?.areaFilter ?? ''}&user_id=${filters.userId}&start_date=${formatStartDate ?? ''}&end_date=${formatEndDate ?? ''}&sort_by=${sortConfig.column ? sortConfig.column : ''}&sort_order=${sortConfig.order ? sortConfig.order : ''}`);
        const dataToExport = response.data.map(({ subscriber_id, invoice_no, customer_name, billing_address, area_name, account_name, paid_amount, paid_date, paid_by }, index) => ({ Sl: index + 1, subscriber_id, invoice_no, customer_name, billing_address, area_name, account_name, paid_amount, paid_date, paid_by }));
        if (response.status === true) {
            const doc = new jsPDF();
            const columns = ["Sl", "Subscriber Id", "Invoice No", "Name", "Address", "Area", "Account", "Amount Paid", "Paid Date", "Paid By"];
            const rows = dataToExport.map(({ subscriber_id, invoice_no, customer_name, billing_address, area_name, account_name, paid_amount, paid_date, paid_by }, index) => [index + 1, subscriber_id, invoice_no, customer_name, billing_address, area_name, account_name, paid_amount, paid_date, paid_by]);
            doc.autoTable({
                head: [columns],
                body: rows,
                columnStyles: {
                    0: { cellWidth: 10 },
                    4: { cellWidth: 30 }
                },
                styles: { fontSize: 10 },
                headStyles: { fillColor: [100, 150, 200] },
            });
            doc.save("online_payment_report.pdf");
        } else {
            handleApiError(data.status);
        }
        setLoading(false);
    };

    return (
        <Fragment>
            {loading && <Transparentspinner />}
            <Breadcrumbs mainTitle={OnlinePaymentRep} parent="Reports" title={OnlinePaymentRep} />
            <Card className='cardWidth'>
                <CardHeader style={{ margin: '-25px 0 -25px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                    <H3>{OnlinePaymentList}</H3>
                    <div>
                        {(authState.userRole === 1 || authState.permissions.includes('export-report')) &&
                            <CardBody className="dropdown-basic">
                                <Dropdown isOpen={dropdownOpen} toggle={toggleDropdown}>
                                    <DropdownToggle color="#fff" style={{ fontSize: '14px', zIndex: 1000 }} className="btn btn-primary mr-4">
                                        {Export} <i className="icofont icofont-arrow-up"></i>
                                    </DropdownToggle>
                                    <DropdownMenu container="body">
                                        <DropdownItem style={toggleStyle} onClick={() => exportOnlinePayExcel()} ><i className="fa fa-file-excel-o me-2"></i> Excel</DropdownItem>
                                        <DropdownItem style={toggleStyle} onClick={() => exportOnlinePayPdf()}><i className="fa fa-file-pdf-o me-2"></i> Pdf</DropdownItem>
                                    </DropdownMenu>
                                </Dropdown>
                            </CardBody>
                        }
                    </div>
                </CardHeader>

                <Form className="needs-validation" noValidate onSubmit={handleSubmit(onSubmit)}>
                    <Row className="ps-3 gap-sm-3 gap-md-2 filterGap">
                        <Col sm="12" md='5' lg='2'>
                            <input className="form-control" placeholder={Search} type="text"
                                {...register('search')} />
                        </Col>
                        <Col sm="12" md="5" lg='2' className="form-element" >
                            <div style={{ position: 'relative', zIndex: 2 }}>
                                <DatePicker
                                    className="form-control digits w-100"
                                    selectsRange
                                    startDate={startDate}
                                    endDate={endDate}
                                    onChange={(update) => {
                                        setDateRange(update);
                                    }}
                                    isClearable={startDate ? true : false}
                                    monthsShown={2}
                                    popperPlacement="bottom"
                                    calendarClassName='parallel-calendar'
                                    placeholderText='Select Date Range'
                                />
                            </div>
                        </Col>
                        <Col sm="12" md="5" lg='2' className="form-element">
                            <AreaDropdown
                                authState={authState}
                                registerName="area"
                                selectedAreaId={filters.area}
                                register={register}
                                setValue={setValue}
                            />
                        </Col>
                        <Col sm="12" md="5" lg='2' className="form-element">
                            <UserDropdown
                                authState={authState}
                                registerName="user"
                                selectedUserId={filters.userId}
                                register={register}
                                setValue={setValue}
                            />
                        </Col>
                        <Col sm="12" md="5" lg='1' className="custom-filtrs">
                            <Btn attrBtn={{ color: "primary" }} type="submit">{Filter}</Btn>
                        </Col>
                    </Row>
                </Form>
                <CardBody>
                    <div className="order-history table-responsive">
                        <DataTable
                            columns={OnlinePaymentColumns(authState)}
                            data={customerLists}
                            onSort={handleSort} // Attach sorting handler here
                            sortServer // Enable server-side sorting
                            pagination
                            paginationServer
                            defaultSortAsc
                            paginationRowsPerPageOptions={[10, 25, 50, 100]}
                            paginationTotalRows={totalRows}
                            paginationDefaultPage={currentPage}
                            onChangeRowsPerPage={handlePerRowsChange}
                            onChangePage={handlePageChange}
                            fixedHeader
                        />
                    </div>
                </CardBody>
            </Card>
        </Fragment>
    );
};

export default OnlinePaymentReport;